UPDATE match_task
SET current_tier = #{tierNo}, status = #{status}, updated_at = NOW()
WHERE id = #{taskId}

UPDATE match_attempt
SET status = #{status}, updated_at = NOW()
WHERE id = #{attemptId}

UPDATE match_attempt
SET status = #{status}, close_reason = #{status}, handled_at = NOW(), updated_at = NOW()
WHERE id = #{attemptId}

UPDATE demand
SET status = #{status}, updated_at = NOW()
WHERE id = #{demandId}
